import React, { useEffect, useState, useRef } from "react";
import { useDispatch, useSelector } from "react-redux";
import {
  SuperAdminfetchDashboardData,
  SuperAdminfetchRecentProducts,
  getProducts,
} from "../../features/product/productSlice";
import { getUserCount } from "../../features/UserList/UserListSlice";
import { getOrders } from "../../features/auth/authSlice";
import { Link } from "react-router-dom";
import { Bar } from "react-chartjs-2";
import {
  RefreshCcw,
  TrendingUp,
  Users,
  ShoppingBag,
  Package,
  ArrowUpRight,
  Activity,
  Zap,
  DollarSign,
  Layers,
} from "lucide-react";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

/* ── Format ETB ── */
const etb = (n) => (n || 0).toLocaleString("en-ET", { maximumFractionDigits: 0 });

const SuperAdminDashboard = () => {
  const dispatch = useDispatch();
  const [loading, setLoading] = useState(true);
  const [lastRefreshed, setLastRefreshed] = useState(new Date());
  const intervalRef = useRef(null);

  /* ── Fetch everything ── */
  const fetchAll = async () => {
    setLoading(true);
    await Promise.all([
      dispatch(SuperAdminfetchDashboardData()),
      dispatch(SuperAdminfetchRecentProducts()),
      dispatch(getUserCount()),
      dispatch(getOrders()),
      dispatch(getProducts()),
    ]);
    setLastRefreshed(new Date());
    setLoading(false);
  };

  useEffect(() => {
    fetchAll();
    intervalRef.current = setInterval(() => {
      dispatch(SuperAdminfetchDashboardData());
      dispatch(SuperAdminfetchRecentProducts());
      dispatch(getUserCount());
      dispatch(getOrders());
      dispatch(getProducts());
      setLastRefreshed(new Date());
    }, 30000); // real-time every 30s
    return () => clearInterval(intervalRef.current);
  }, [dispatch]);

  const recentProducts = useSelector((s) => s.product.recentProducts?.data || []);
  const orderState     = useSelector((s) => s.auth.orders?.orders || []);
  const productState   = useSelector((s) => s.product?.products || []);
  const userCounts     = useSelector((s) => s.userList.userCounts?.data || {});

  /* ── Derived stats ── */
  const totalRevenue   = orderState.reduce((sum, o) => sum + (o.totalPriceAfterDiscount || 0), 0);
  const totalSales     = orderState.length;
  const totalProducts  = productState.length;
  const pendingProducts = recentProducts.filter((p) => p.status === "pending").length;

  /* ── Charts ── */
  const userChartData = {
    labels: ["Customers", "Merchants", "Admins", "Fleet"],
    datasets: [{
      label: "System Volume",
      data: [userCounts.customer || 0, userCounts.merchant || 0, userCounts.admin || 0, userCounts.deliveryBoy || 0],
      backgroundColor: ["#3b82f6", "#8b5cf6", "#f59e0b", "#ef4444"],
      borderRadius: 12,
      borderSkipped: false,
    }],
  };

  const chartOpts = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: { legend: { display: false } },
    scales: {
      x: { grid: { display: false }, ticks: { font: { weight: "800", size: 10 }, color: "#94a3b8" } },
      y: { grid: { borderDash: [4, 4], color: "#f1f5f9" }, ticks: { font: { size: 10 }, color: "#94a3b8" }, beginAtZero: true },
    },
  };

  return (
    <div className="space-y-12 animate-in fade-in zoom-in-95 duration-700">
      {/* Premium Station Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
        <div className="space-y-2">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-1.5 h-1.5 rounded-full bg-blue-600 animate-pulse" />
            <span className="text-[11px] font-black text-blue-600 uppercase tracking-[0.3em]">Command Center</span>
          </div>
          <h1 className="text-[48px] font-black text-slate-900 tracking-tighter leading-none">
            System <span className="text-blue-600">Telemetry</span>
          </h1>
          <p className="text-[16px] text-slate-400 font-bold max-w-xl italic">
            "Real-time surveillance of Pulse Addis infrastructure and commercial flow."
          </p>
        </div>
        
        <div className="flex items-center gap-4">
           <div className="bg-white px-6 py-4 rounded-[28px] border border-slate-100 shadow-sm flex items-center gap-4 group hover:border-blue-200 transition-all cursor-default">
              <div className="w-10 h-10 rounded-xl bg-blue-50 text-blue-600 flex items-center justify-center group-hover:rotate-12 transition-transform">
                 <RefreshCcw size={20} className={loading ? "animate-spin" : ""} onClick={fetchAll} />
              </div>
              <div>
                 <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest leading-none">Last Sync</p>
                 <p className="text-[14px] text-slate-900 font-black mt-1">{lastRefreshed.toLocaleTimeString()}</p>
              </div>
           </div>
        </div>
      </div>

      {/* KPI Command Matrix */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6">
         {[
           { label: "Revenue Matrix", value: `ETB ${etb(totalRevenue)}`, icon: <DollarSign />, color: "text-emerald-600", bg: "bg-emerald-50", trend: "7.2%" },
           { label: "Traffic Volume", value: totalSales, icon: <ShoppingBag />, color: "text-blue-600", bg: "bg-blue-50", trend: "+12" },
           { label: "Inventory Map", value: totalProducts, icon: <Package />, color: "text-indigo-600", bg: "bg-indigo-50", trend: `${pendingProducts} Pending` },
           { label: "Citizen Pulse", value: (userCounts.customer || 0) + (userCounts.merchant || 0), icon: <Users />, color: "text-amber-600", bg: "bg-amber-50", trend: "Active" }
         ].map((kpi, i) => (
           <div key={i} className="enterprise-card p-8 group">
              <div className="flex justify-between items-start mb-6">
                 <div className={`w-14 h-14 ${kpi.bg} ${kpi.color} rounded-2xl flex items-center justify-center shadow-sm group-hover:scale-110 transition-transform duration-500`}>
                    {React.cloneElement(kpi.icon, { size: 28 })}
                 </div>
                 <div className="flex flex-col items-end">
                    <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest">{kpi.label}</span>
                    <div className="flex items-center gap-1 text-emerald-500 mt-1">
                       <ArrowUpRight size={14} strokeWidth={3} />
                       <span className="text-[12px] font-black tracking-tighter">{kpi.trend}</span>
                    </div>
                 </div>
              </div>
              <h2 className="text-[32px] font-black text-slate-900 tracking-tighter leading-none mb-2">
                {loading ? "..." : kpi.value}
              </h2>
              <div className="w-full h-1 bg-slate-50 rounded-full overflow-hidden mt-6">
                 <div className={`h-full ${kpi.bg.replace('bg-', 'bg-')} opacity-60 w-2/3`} />
              </div>
           </div>
         ))}
      </div>

      {/* Intelligence Sector */}
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
         {/* User Chart */}
         <div className="xl:col-span-2 enterprise-card p-10">
            <div className="flex items-center justify-between mb-10">
               <div className="flex items-center gap-4">
                  <div className="w-12 h-12 rounded-2xl bg-slate-900 text-white flex items-center justify-center shadow-lg">
                     <Activity size={24} />
                  </div>
                  <div>
                     <h3 className="text-[20px] font-black text-slate-900 leading-none uppercase tracking-tighter">Citizen Distribution</h3>
                     <p className="text-[12px] text-slate-400 font-bold mt-1 uppercase tracking-widest">Active nodes across the sector</p>
                  </div>
               </div>
               <button className="text-[11px] font-black text-blue-600 uppercase tracking-widest hover:underline">Download Audit</button>
            </div>
            
            <div style={{ height: 320 }}>
               <Bar data={userChartData} options={chartOpts} />
            </div>
         </div>

         {/* Sector Bulletin */}
         <div className="bg-slate-900 rounded-[48px] p-12 text-white relative overflow-hidden group shadow-2xl">
            <div className="absolute top-0 right-0 p-12 opacity-5 group-hover:scale-110 transition-transform duration-[2s]">
               <Zap size={240} />
            </div>
            <div className="relative z-10 flex flex-col h-full justify-between">
               <div className="space-y-8">
                  <div className="w-16 h-16 bg-white/10 rounded-3xl flex items-center justify-center backdrop-blur-3xl border border-white/5 shadow-2xl">
                     <TrendingUp size={32} className="text-blue-400" />
                  </div>
                  <div className="space-y-4">
                     <h4 className="text-[28px] font-black tracking-tighter uppercase leading-tight">Growth <br/> Protocol 4.2</h4>
                     <p className="text-[15px] text-slate-400 leading-relaxed font-bold">
                        Platform traffic has surged by <span className="text-white font-black underline underline-offset-4 decoration-blue-500">18.4%</span> this cycle. Deploy new merchant subsidies to maintain momentum.
                     </p>
                  </div>
               </div>
               <div className="pt-12 grid grid-cols-2 gap-4">
                  <div className="p-4 rounded-3xl bg-white/5 border border-white/5">
                     <p className="text-[24px] font-black tracking-tighter">8.4k</p>
                     <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Daily Hits</p>
                  </div>
                  <div className="p-4 rounded-3xl bg-white/5 border border-white/5">
                     <p className="text-[24px] font-black tracking-tighter">98.2%</p>
                     <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest">Uptime</p>
                  </div>
               </div>
            </div>
         </div>
      </div>

      {/* Recent Activity Ledger */}
      <div className="enterprise-card overflow-hidden">
         <div className="p-10 border-b border-slate-50 flex items-center justify-between bg-slate-50/20">
            <div className="flex items-center gap-4">
               <div className="w-12 h-12 rounded-2xl bg-indigo-600 text-white flex items-center justify-center shadow-lg">
                  <Layers size={24} />
               </div>
               <div>
                  <h3 className="text-[20px] font-black text-slate-900 leading-none uppercase tracking-tighter">Recent SKU Feed</h3>
                  <p className="text-[12px] text-slate-400 font-bold mt-1 uppercase tracking-widest">Awaiting verification or recently indexed</p>
               </div>
            </div>
            <Link to="list-product" className="h-12 flex items-center px-6 rounded-2xl font-black uppercase text-[11px] tracking-widest bg-slate-100 text-slate-600 hover:bg-slate-900 hover:text-white transition-all">
               Deep Catalog →
            </Link>
         </div>

         <div className="overflow-x-auto">
            <table className="w-full text-left">
               <thead>
                  <tr className="border-b border-slate-50">
                     <th className="px-10 py-6 text-[11px] font-black text-slate-400 uppercase tracking-widest">Entity</th>
                     <th className="px-10 py-6 text-[11px] font-black text-slate-400 uppercase tracking-widest">Classification</th>
                     <th className="px-10 py-6 text-[11px] font-black text-slate-400 uppercase tracking-widest">Commercial</th>
                     <th className="px-10 py-6 text-[11px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                     <th className="px-10 py-6 text-[11px] font-black text-slate-400 uppercase tracking-widest">Index Date</th>
                  </tr>
               </thead>
               <tbody className="divide-y divide-slate-50">
                  {recentProducts.slice(0, 6).map((p) => (
                    <tr key={p._id} className="group hover:bg-slate-50 transition-colors">
                       <td className="px-10 py-6">
                          <div className="flex items-center gap-4">
                             <div className="w-14 h-14 rounded-2xl overflow-hidden border border-slate-100 bg-white p-1">
                                <img src={(Array.isArray(p.colors?.[0]?.images) ? p.colors?.[0]?.images?.[0]?.secure_url : p.colors?.[0]?.images?.secure_url) || ""} className="w-full h-full object-cover rounded-xl" />
                             </div>
                             <div>
                                <p className="text-[15px] font-black text-slate-900 leading-none transition-colors group-hover:text-blue-600">{p.title}</p>
                                <p className="text-[12px] text-slate-400 font-bold mt-1 uppercase tracking-widest">{p.brand}</p>
                             </div>
                          </div>
                       </td>
                       <td className="px-10 py-6">
                          <span className="px-4 py-1.5 rounded-xl bg-slate-100 text-slate-600 text-[11px] font-black uppercase tracking-widest">
                             {p.category}
                          </span>
                       </td>
                       <td className="px-10 py-6 font-black text-slate-900 text-[15px]">
                          ETB {etb(p.price)}
                       </td>
                       <td className="px-10 py-6">
                          <div className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-[11px] font-black uppercase tracking-widest ${
                             p.status === 'approved' ? 'bg-emerald-50 text-emerald-600' : 
                             p.status === 'rejected' ? 'bg-rose-50 text-rose-600' : 'bg-amber-50 text-amber-600'
                          }`}>
                             <div className={`w-1.5 h-1.5 rounded-full animate-pulse ${
                                p.status === 'approved' ? 'bg-emerald-500' : 
                                p.status === 'rejected' ? 'bg-rose-500' : 'bg-amber-500'
                             }`} />
                             {p.status || 'Pending'}
                          </div>
                       </td>
                       <td className="px-10 py-6 text-[13px] text-slate-400 font-bold">
                          {new Date(p.createdAt).toLocaleDateString()}
                       </td>
                    </tr>
                  ))}
               </tbody>
            </table>
         </div>
      </div>
    </div>
  );
};

export default SuperAdminDashboard;
